// friday13.cs — Friday the 13th explorer (proleptic Gregorian calendar)

// 1) Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateTime(1, 1, 13); // start checking the 13th of each month
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// 2) Count Friday the 13ths in a full 400-year Gregorian cycle (years 1–400)
//    The Gregorian calendar repeats exactly every 400 years.
int count = 0;
var d = new DateTime(1, 1, 13);
var end = new DateTime(401, 1, 1);

while (d < end)
{
    if (d.DayOfWeek == DayOfWeek.Friday)
        count++;
    d = d.AddMonths(1);
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// 3) Bonus: distribution by day-of-week for the 13th across 400 years
var dayCounts = new int[7];
d = new DateTime(1, 1, 13);
while (d < end)
{
    dayCounts[(int)d.DayOfWeek]++;
    d = d.AddMonths(1);
}

Console.WriteLine("\nDay-of-week distribution for the 13th (400-year cycle):");
foreach (DayOfWeek dow in Enum.GetValues<DayOfWeek>())
    Console.WriteLine($"  {dow,-10} {dayCounts[(int)dow],4}  {(dayCounts[(int)dow] == dayCounts.Max() ? "<-- most common!" : "")}");

